const STORAGE_KEY = 'school_scheduler_master_v1';

export default function App() {
  const initData = (): HistoryState => {
    try {
      const local = localStorage.getItem(STORAGE_KEY);
      if (local) {
        const parsed = JSON.parse(local);
        const mergedState = deepMerge(DEFAULT_STATE, parsed);
        return { past: [], present: mergedState, future: [] };
      }
    } catch (e) { console.error(e); }
    return { past: [], present: DEFAULT_STATE, future: [] };
  };

  const [store, dispatch] = useReducer(reducer, {}, initData);
  const [activePage, setActivePage] = useState('dashboard');
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [showSplash, setShowSplash] = useState(true);
  const [hasSelectedProject, setHasSelectedProject] = useState(false);

  // --- Live Theme & Color Effect ---
  useEffect(() => {
    const { theme, primaryColor } = store.present.ui;
    const root = window.document.documentElement;

    // 1. Theme Logic
    const applyTheme = (t: AppTheme) => {
      if (t === 'dark') {
        root.classList.add('dark');
      } else if (t === 'light') {
        root.classList.remove('dark');
      } else {
        const isDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
        root.classList.toggle('dark', isDark);
      }
    };
    applyTheme(theme);

    // 2. Primary Color Logic (Live update of CSS Variables)
    root.style.setProperty('--primary-500', primaryColor);
    // Rough generation of shades for better UI depth
    root.style.setProperty('--primary-50', `${primaryColor}10`);
    root.style.setProperty('--primary-100', `${primaryColor}25`);
    root.style.setProperty('--primary-400', `${primaryColor}cc`);
    root.style.setProperty('--primary-600', `${primaryColor}e6`);
    root.style.setProperty('--primary-700', `${primaryColor}ff`);

  }, [store.present.ui]);

  useEffect(() => {
    if (hasSelectedProject) {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(store.present));
    }
  }, [store.present, hasSelectedProject]);

  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  const addToast = (type: ToastMessage['type'], message: string) => {
    const id = generateId();
    setToasts(prev => [...prev, { id, type, message }]);
  };
  const removeToast = (id: string) => setToasts(prev => prev.filter(t => t.id !== id));

  const handleNewProject = () => {
      setHasSelectedProject(true);
      addToast('info', 'نوی پروجکټ پیل شو');
  };

  const handleImportProject = (data: any) => {
      dispatch({ type: 'INIT', payload: data });
      setHasSelectedProject(true);
      addToast('success', 'پخوانی پروجکټ په بریالیتوب سره خلاص شو');
  };

  const renderPage = () => {
    if (activePage === 'print-preview') {
        return <PrintPreviewPage onBack={() => setActivePage('data')} />;
    }

    switch(activePage) {
      case 'dashboard': return <Dashboard />;
      case 'teachers': return <Teachers />;
      case 'classes': return <Classes />;
      case 'settings': return <SettingsPage />;
      case 'design': return <DesignPage />;
      case 'data': return <DataMgmt setPage={setActivePage} />;
      case 'help': return <HelpPage />;
      default: return <Dashboard />;
    }
  };

  const contextValue = {
    state: store.present,
    dispatch,
    canUndo: store.past.length > 0,
    canRedo: store.future.length > 0,
    toasts,
    addToast,
    removeToast
  };

  const isPreviewMode = activePage === 'print-preview';

  return (
    <AppContext.Provider value={contextValue}>
      <AnimatePresence>
        {showSplash && <SplashScreen />}
