                        </div>
                </header>
            )}

            {isMobileMenuOpen && !isPreviewMode && (
                <div className="fixed inset-0 bg-black/50 z-30 lg:hidden backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
            )}

            <main className={`flex-1 overflow-auto bg-slate-50 dark:bg-slate-950 transition-colors duration-300 ${isPreviewMode ? 'p-0' : 'p-4 lg:p-6'}`}>
                {renderPage()}
            </main>
            </div>

            <div className="toast-container">
                <Toast toasts={toasts} removeToast={removeToast} />
            </div>

            <div id="export-canvas-container" style={{ width: '2000px', boxSizing: 'border-box' }}>
                <TimetableTemplate state={store.present} />
            </div>

        </div>
      )}
    </AppContext.Provider>
  );
}

import React, { useContext, useMemo, useState } from 'react';
import { AppContext } from '../App';
import { calculateTimeSlots, detectConflicts, generateOptimizationProposals } from '../utils';
import { Undo, Redo, Wand2, Users, GraduationCap, AlertTriangle, Maximize2, Minimize2, X } from 'lucide-react';
import { Schedule } from '../types';
import TimetableGrid from './TimetableGrid';
import OptimizationModal from './OptimizationModal';

const Dashboard: React.FC = () => {
  const { state, dispatch, canUndo, canRedo, addToast } = useContext(AppContext);
  const { teachers, classes, schedule, settings } = state;

  const timeSlots = useMemo(() => calculateTimeSlots(settings), [settings]);
  const conflicts = useMemo(() => detectConflicts(schedule, teachers, classes, timeSlots), [schedule, teachers, classes, timeSlots]);
  const conflictCount = Object.keys(conflicts).length;

  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Optimization Proposals State
  const [showOptModal, setShowOptModal] = useState(false);
  const [optProposals, setOptProposals] = useState<{id: string, schedule: Schedule, conflictCount: number}[]>([]);

  const handleOptimizeStart = async () => {
    setIsOptimizing(true);
    setTimeout(() => {
        try {
            const proposals = generateOptimizationProposals(schedule, classes, timeSlots);
            if (proposals.length === 0) {
                addToast('info', 'اوسنی مهال ویش لا دمخه غوره دی');
            } else {
                setOptProposals(proposals);
                setShowOptModal(true);
            }
        } catch (e) {
            console.error(e);
            addToast('error', 'د سمون په پروسه کې تېروتنه وشوه');
        } finally {
            setIsOptimizing(false);
        }
    }, 100);
  };

  const handleApplyOptimization = (newSchedule: Schedule) => {
      dispatch({ type: 'RECORD' }); 
      dispatch({ type: 'REPLACE_SCHEDULE', payload: newSchedule });
      addToast('success', 'مهال ویش په بریالیتوب سره تازه شو');
      setShowOptModal(false);
  };

  return (
    <div className="flex flex-col h-full gap-6">
      {!isFullScreen && (
        <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 transition-colors">
            <div className="flex flex-wrap gap-4">
            <StatBadge icon={<Users size={18} />} label="ښوونکي" value={teachers.length} color="bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400" />
            <StatBadge icon={<GraduationCap size={18} />} label="ټولګي" value={classes.length} color="bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400" />
            <StatBadge 
                icon={<AlertTriangle size={18} />} 
                label="تضاد" 
                value={conflictCount} 
                color={conflictCount > 0 ? "bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400" : "bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400"} 
            />
            </div>

            <div className="flex gap-2 w-full md:w-auto">
            <div className="flex gap-1 bg-slate-100 dark:bg-slate-700 p-1 rounded-lg">
                <button 
                    onClick={() => dispatch({ type: 'UNDO' })} 
                    disabled={!canUndo}
                    className="p-2 hover:bg-white dark:hover:bg-slate-600 rounded-md disabled:opacity-30 transition-all text-slate-600 dark:text-slate-300"
                    title="شاته (Undo)"
                >
                    <Undo size={20} />
                </button>
                <button 
                    onClick={() => dispatch({ type: 'REDO' })} 
                    disabled={!canRedo}
                    className="p-2 hover:bg-white dark:hover:bg-slate-600 rounded-md disabled:opacity-30 transition-all text-slate-600 dark:text-slate-300"
                    title="بیا کول (Redo)"
                >
                    <Redo size={20} />
                </button>
            </div>

            <button 
                onClick={() => setIsFullScreen(true)}
                className="p-2 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 text-slate-600 dark:text-slate-300 rounded-lg transition-colors"
                title="پوره سکرین (Full Screen)"
            >
                <Maximize2 size={20} />
            </button>

            <button
                onClick={handleOptimizeStart}
                disabled={isOptimizing}
                className="flex-1 md:flex-none flex items-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 hover:from-primary-700 hover:to-primary-600 text-white px-6 py-2 rounded-lg shadow-md hover:shadow-lg transition-all disabled:opacity-70"
            >
                <Wand2 size={18} className={isOptimizing ? "animate-spin" : ""} />
                <span>{isOptimizing ? 'په پروسه کې...' : 'هوښیار سمون'}</span>
            </button>
            </div>
        </div>
      )}

      <div className={`
        ${isFullScreen 
            ? 'fixed inset-0 z-50 bg-slate-100 dark:bg-slate-950 p-8 flex flex-col items-center justify-center' 
            : 'flex-1 bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden relative'
        }
      `}>
         {isFullScreen && (
            <div className="absolute top-4 right-4 z-50 flex gap-2">
                 <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur px-4 py-2 rounded-full shadow-sm text-slate-600 dark:text-slate-300 font-bold text-sm">
                    د بشپړ سکرین حالت
                 </div>
                 <button 
                    onClick={() => setIsFullScreen(false)}
                    className="p-2 bg-red-100 dark:bg-red-900 text-red-600 dark:text-red-400 hover:bg-red-200 dark:hover:bg-red-800 rounded-full transition-colors shadow-sm"
                 >
                    <X size={24} />
                 </button>
            </div>
         )}

         <div className={`w-full h-full overflow-hidden ${isFullScreen ? 'max-w-[95vw] max-h-[90vh] bg-white dark:bg-slate-800 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-700 flex flex-col' : ''}`}>
             <TimetableGrid 
                classes={classes}
                slots={timeSlots}
                schedule={schedule}
                conflicts={conflicts}
                teachers={teachers}
                design={state.design}
             />
         </div>
      </div>

      <OptimizationModal 
        isOpen={showOptModal}
        onClose={() => setShowOptModal(false)}
        onApply={handleApplyOptimization}
        proposals={optProposals}
        classes={classes}
        slots={timeSlots}
        teachers={teachers}
        design={state.design}
      />
    </div>
  );
};

const StatBadge = ({ icon, label, value, color }: any) => (
  <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full ${color} font-medium text-sm transition-colors`}>
    {icon}
    <span>{label}: {value}</span>
  </div>
);

export default Dashboard;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { ClassGroup, TimeSlot, Schedule, Teacher, DesignSettings, LessonData } from '../types';
import { Plus, Coffee, AlertCircle } from 'lucide-react';
import { getContrastColor } from '../utils';
import EditModal from './EditModal';

interface Props {
  classes: ClassGroup[];
  slots: TimeSlot[];
  schedule: Schedule;
  conflicts: { [key: string]: boolean };
  teachers: Teacher[];
  design: DesignSettings;
  readOnly?: boolean;
}

const TimetableGrid: React.FC<Props> = ({ classes, slots, schedule, conflicts, teachers, design, readOnly = false }) => {
  const { dispatch } = useContext(AppContext);

  const [editingCell, setEditingCell] = useState<{ key: string, data: LessonData | null } | null>(null);
  const [dragSource, setDragSource] = useState<string | null>(null);
  const [dragOverKey, setDragOverKey] = useState<string | null>(null);

  const handleCellClick = (key: string) => {
    if (readOnly) return;
    setEditingCell({ key, data: schedule[key] || null });
  };

  const handleSaveLesson = (data: LessonData) => {
    if (readOnly) return;
    if (editingCell) {
      dispatch({ type: 'SET_LESSON', payload: { key: editingCell.key, data } });
    }
  };

  const handleDeleteLesson = () => {
    if (readOnly) return;
    if (editingCell) {
      dispatch({ type: 'SET_LESSON', payload: { key: editingCell.key, data: null } });
      setEditingCell(null);
    }
  };

  const onDragStart = (e: React.DragEvent, key: string) => {
    if (readOnly) {
        e.preventDefault();
        return;
    }
    if (!schedule[key]) {
        e.preventDefault();
        return;
    }
    setDragSource(key);
    e.dataTransfer.effectAllowed = 'move';
  };

  const onDragOver = (e: React.DragEvent, key: string) => {
    e.preventDefault(); 
    if (readOnly) return;
    const sourceClass = dragSource?.split('_')[0];
    const targetClass = key.split('_')[0];
    if (sourceClass === targetClass) {
        setDragOverKey(key);
        e.dataTransfer.dropEffect = 'move';
    } else {
        e.dataTransfer.dropEffect = 'none';
    }
  };

  const onDrop = (e: React.DragEvent, targetKey: string) => {
    e.preventDefault();
    if (readOnly) return;
    if (dragSource && dragSource !== targetKey) {
        const sourceClass = dragSource.split('_')[0];
        const targetClass = targetKey.split('_')[0];
        if (sourceClass === targetClass) {
            dispatch({ type: 'MOVE_LESSON', payload: { fromKey: dragSource, toKey: targetKey } });
        }
    }
    setDragSource(null);
    setDragOverKey(null);
  };

  const getTeacher = (id: string) => teachers.find(t => t.id === id);

  return (
    <>
      <div className="w-full h-full overflow-auto bg-white dark:bg-slate-900 rounded-lg transition-colors">
        <div className="inline-block min-w-max">
          {/* Header Row */}
          <div className="flex sticky-header bg-slate-50 dark:bg-slate-800 shadow-sm border-b border-slate-200 dark:border-slate-700 z-20 transition-colors">
            <div className="sticky-col left-0 w-32 p-3 font-bold text-slate-700 dark:text-slate-200 bg-slate-50 dark:bg-slate-800 border-l border-slate-200 dark:border-slate-700 text-center flex items-center justify-center shadow-[4px_0_10px_-5px_rgba(0,0,0,0.1)] z-30 transition-colors">
              ټولګي
            </div>
            {slots.map((slot) => (
              <div key={slot.id} className="w-36 p-2 text-center border-l border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 transition-colors">
                <div className="text-sm font-bold text-slate-800 dark:text-slate-100">{slot.label}</div>
                <div className="text-[10px] text-slate-500 dark:text-slate-400 mt-0.5 bg-slate-200 dark:bg-slate-700 inline-block px-1.5 rounded">
                  {slot.start} - {slot.end}
                </div>
              </div>
            ))}
          </div>

          {/* Rows */}
          {classes.map((cls) => (
            <div key={cls.id} className="flex border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
              {/* Sticky Class Name */}
              <div className="sticky-col left-0 w-32 p-2 font-bold text-sm text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 flex items-center justify-center shadow-[4px_0_10px_-5px_rgba(0,0,0,0.1)] z-10 transition-colors">
                <div className="truncate px-1">{cls.name}</div>
              </div>

              {/* Cells */}
              {slots.map((slot) => {
                const key = `${cls.id}_${slot.id}`;
                const lesson = schedule[key];
                const isConflict = conflicts[key];
                const isBreak = slot.type === 'break';
                const isDraggingOver = dragOverKey === key;

                const style = isBreak ? design.break : design.lesson;
                const teacher = lesson ? getTeacher(lesson.teacherId) : null;
                const tColor = teacher ? teacher.color : '#ccc';
                const tContrast = teacher ? getContrastColor(tColor) : '#000';

                if (isBreak) {
                  return (
                    <div key={key} className="w-36 p-1 border-l border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20 flex items-center justify-center opacity-80">
                         <div 
                            className="w-full h-full flex flex-col items-center justify-center gap-1 rounded text-slate-400 dark:text-slate-500"
                            style={{
                                backgroundColor: style.backgroundColor,
                                border: `${style.borderWidth}px ${style.borderStyle} ${style.borderColor}`,
                                borderRadius: `${style.borderRadius}px`,
                            }}
                         >
                            <Coffee size={16} />
                         </div>
                    </div>
                  );
                }

                return (
                  <div 
                    key={key} 
                    className={`
                        w-36 p-0.5 border-l border-slate-100 dark:border-slate-800 relative group transition-colors
                        ${isDraggingOver ? 'bg-primary-50 dark:bg-primary-900/20' : ''}
                    `}
                    onDragOver={(e) => onDragOver(e, key)}
                    onDrop={(e) => onDrop(e, key)}
                  >
                    <div 
                        onClick={() => handleCellClick(key)}
                        draggable={!!lesson && !readOnly}
                        onDragStart={(e) => onDragStart(e, key)}
                        className={`
                            w-full h-full min-h-[60px] flex flex-col items-center justify-center text-center relative transition-all transform
                            ${readOnly ? '' : 'cursor-pointer'}
                            ${lesson && !readOnly ? 'hover:scale-[1.02] hover:shadow-md' : ''}
                            ${!lesson && !readOnly ? 'hover:bg-slate-50 dark:hover:bg-slate-800' : ''}
                            ${isConflict ? 'ring-2 ring-red-500 animate-pulse' : ''}
                        `}
                        style={{
                            backgroundColor: style.backgroundColor, 
                            color: 'inherit',
                            border: lesson 
                                ? `${style.borderWidth}px ${style.borderStyle} ${isConflict ? '#ef4444' : style.borderColor}`
                                : '1px dashed #e2e8f0',
                            borderRadius: `${style.borderRadius}px`,
                            boxShadow: lesson ? style.shadow : 'none',
                            fontSize: `${style.fontSize}px`,
                            margin: `${style.margin}px`
                        }}
                    >
                        {lesson ? (
                            <>
                                <div className="font-bold leading-tight mb-1 px-1 truncate w-full text-slate-800 dark:text-slate-100">{lesson.subject}</div>
                                {teacher && (
                                    <div 
                                        className="text-[0.75em] px-2 py-0.5 rounded-full max-w-[90%] truncate font-medium"
                                        style={{
                                            backgroundColor: tColor,
                                            color: tContrast
                                        }}
                                    >
                                        {teacher.name}
                                    </div>
                                )}
                                {isConflict && (
                                    <div className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5 shadow-sm z-10">
                                        <AlertCircle size={10} />
                                    </div>
                                )}
                            </>
                        ) : (
                            !readOnly && <Plus className="text-slate-300 dark:text-slate-600 w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity" />
                        )}
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
      {!readOnly && (
          <EditModal 
            isOpen={!!editingCell}
            initialData={editingCell?.data}
            teachers={teachers}
            onClose={() => setEditingCell(null)}
            onSave={handleSaveLesson}
            onDelete={handleDeleteLesson}
          />
      )}
    </>
  );
};

export default TimetableGrid;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Trash2, Check } from 'lucide-react';
import { Teacher, LessonData } from '../types';

interface EditModalProps {
  isOpen: boolean;
  initialData?: LessonData | null;
  teachers: Teacher[];
  onClose: () => void;
  onSave: (data: LessonData) => void;
  onDelete: () => void;
}

const EditModal: React.FC<EditModalProps> = ({ 
  isOpen, initialData, teachers, onClose, onSave, onDelete 
}) => {
  const [subject, setSubject] = useState('');
  const [teacherId, setTeacherId] = useState('');

  useEffect(() => {
    if (isOpen) {
      setSubject(initialData?.subject || '');
      setTeacherId(initialData?.teacherId || '');
    }
  }, [isOpen, initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (subject && teacherId) {
      onSave({ subject, teacherId });
      onClose();
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
            onClick={onClose}
          />
          <motion.div 
            initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 50, opacity: 0 }}
            className="relative bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-sm p-6 border border-slate-200 dark:border-slate-700 transition-colors"
          >
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-gray-800 dark:text-white">لوست سمول</h2>
              <button onClick={onClose} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">د لوست نوم</label>
                <input 
                  type="text" 
                  value={subject}
                  onChange={(e) => setSubject(e.target.value)}
                  className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all dark:text-white"
                  placeholder="مثال: ریاضی، پښتو..."
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">ښوونکی وټاکئ</label>
                <select 
                  value={teacherId}
                  onChange={(e) => setTeacherId(e.target.value)}
                  className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all dark:text-white"
                >
                  <option value="">یو ښوونکی وټاکئ</option>
                  {teachers.map(t => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                  ))}
                </select>
              </div>

              <div className="flex gap-3 pt-4">
                {initialData && (
                  <button 
                    type="button"
                    onClick={onDelete}
                    className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                    title="لوست لرې کول"
                  >
                    <Trash2 size={20} />
                  </button>
                )}
                <button 
                  type="submit"
                  disabled={!subject || !teacherId}
                  className="flex-1 flex items-center justify-center gap-2 bg-primary-600 hover:bg-primary-700 text-white py-2 px-4 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-bold"
                >
                  <Check size={18} />
                  <span>بدلونونه ثبت کړئ</span>
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default EditModal;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { Plus, Trash2, Edit2, Check, X, Palette, Shuffle } from 'lucide-react';
import { generateId } from '../utils';
import { COLORS } from '../types';
import ConfirmModal from './ConfirmModal';

const Teachers: React.FC = () => {
  const { state, dispatch, addToast } = useContext(AppContext);
