    addToast('success', 'د ښوونکي نوم سم شو');
  };

  const confirmDelete = () => {
    if (deleteId) {
        dispatch({ type: 'DELETE_TEACHER', payload: deleteId });
        addToast('success', 'ښوونکی حذف شو');
        setDeleteId(null);
