        <div className="flex flex-col gap-4">
            <div className="flex gap-4">
                <input 
                type="text" 
                value={newTeacherName}
                onChange={(e) => setNewTeacherName(e.target.value)}
                placeholder="د نوي ښوونکي نوم..."
                className="flex-1 px-4 py-3 bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none dark:text-white transition-all"
                />
                <button 
                    type="submit"
                    disabled={!newTeacherName.trim()}
                    className="bg-primary-600 hover:bg-primary-700 text-white px-6 rounded-xl flex items-center gap-2 disabled:opacity-50 transition-colors whitespace-nowrap font-bold"
                >
                    <Plus size={20} />
                    <span>زیاتول</span>
