            <div className="flex items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl transition-colors">
                <span className="text-sm font-bold text-slate-600 dark:text-slate-400">رنګ ټاکل:</span>
                <div className="flex gap-2">
