                        type="button"
                        onClick={() => setColorMode('random')}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-lg text-sm transition-colors border ${
                            colorMode === 'random' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-sm ring-1 ring-primary-500' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Shuffle size={14} />
                        <span>تصادفي</span>
                    </button>
                    <button
                        type="button"
                        onClick={() => setColorMode('custom')}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-lg text-sm transition-colors border ${
                            colorMode === 'custom' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-sm ring-1 ring-primary-500' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Palette size={14} />
                        <span>دودیز</span>
                    </button>
                </div>
                {colorMode === 'custom' && (
                    <div className="flex items-center gap-2 animate-in fade-in duration-300">
                        <input 
                            type="color" 
                            value={customColor} 
                            onChange={(e) => setCustomColor(e.target.value)}
                            className="w-8 h-8 rounded cursor-pointer border-2 border-white dark:border-slate-700 shadow-sm" 
                        />
                        <span className="text-xs text-slate-400 dark:text-slate-500" dir="ltr">{customColor}</span>
                    </div>
                )}
            </div>
        </div>
      </form>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {state.teachers.map(t => (
            <div key={t.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-center justify-between group transition-colors">
                {editingId === t.id ? (
                    <div className="flex items-center gap-2 w-full">
                        <input 
                            type="text" 
                            value={editName} 
                            onChange={(e) => setEditName(e.target.value)}
                            className="flex-1 px-2 py-1 border dark:border-slate-600 rounded bg-slate-50 dark:bg-slate-900 dark:text-white"
                            autoFocus
                        />
                        <button onClick={() => saveEdit(t)} className="text-green-600 p-1 bg-green-50 dark:bg-green-900/20 rounded hover:bg-green-100 dark:hover:bg-green-800/40"><Check size={16} /></button>
                        <button onClick={() => setEditingId(null)} className="text-slate-400 p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"><X size={16} /></button>
                    </div>
                ) : (
                    <>
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full flex items-center justify-center text-white font-bold shadow-sm border-2 border-white dark:border-slate-700" style={{ backgroundColor: t.color }}>
                                {t.name.charAt(0)}
                            </div>
                            <span className="font-medium text-slate-700 dark:text-slate-200">{t.name}</span>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => startEdit(t)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors">
                                <Edit2 size={18} />
                            </button>
                            <button onClick={() => setDeleteId(t.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors">
                                <Trash2 size={18} />
                            </button>
                        </div>
                    </>
                )}
            </div>
        ))}
      </div>
      <ConfirmModal 
        isOpen={!!deleteId}
        message="د دې ښوونکي په لرې کولو سره به د هغه ټول اړوند لوستونه له مهال ویش څخه لرې شي. ایا دوام ورکوئ؟"
        onCancel={() => setDeleteId(null)}
        onConfirm={confirmDelete}
      />
    </div>
  );
};

export default Teachers;
